code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Input, Select, Button, Chip, icon } from 'decantr/components';

code.example:
function SearchFilterBar({ query, type, namespace, sort, onSearch, onTypeChange, onNamespaceChange, onSortChange }) {
  const { div, span } = tags;
  const types = ['all', 'patterns', 'themes', 'blueprints', 'archetypes', 'recipes', 'shells'];

  return div({ class: css('_flex _col _gap4') },
    div({ class: css('_flex _aic _gap3') },
      div({ class: css('_flex _aic _gap2 _flex1 _border _bordermuted/20 _r2 _px3 _py2') },
        icon('search', { size: '1rem', class: css('_fgmuted') }),
        Input({ type: 'text', value: query, placeholder: 'Search registry...', class: css('_flex1 _border0 _outline0 _bgcanvas _textsm'), oninput: (e) => onSearch(e.target.value) }),
        query ? Button({ variant: 'ghost', size: 'xs', onclick: () => onSearch('') }, icon('x', { size: '0.875rem' })) : null
      )
    ),
    div({ class: css('_flex _aic _jcsb _gap4') },
      div({ class: css('_flex _gap2 _overflow-x-auto') },
        ...types.map(t =>
          Chip({ variant: t === type ? 'primary' : 'outline', size: 'sm', onclick: () => onTypeChange(t) },
            t === 'all' ? 'All' : t.charAt(0).toUpperCase() + t.slice(1)
          )
        )
      ),
      div({ class: css('_flex _gap2 _shrink0') },
        Select({ size: 'sm', value: namespace, onchange: (e) => onNamespaceChange(e.target.value) },
          { value: '', label: 'All namespaces' },
          { value: '@official', label: '@official' },
          { value: '@community', label: '@community' }
        ),
        Select({ size: 'sm', value: sort, onchange: (e) => onSortChange(e.target.value) },
          { value: 'newest', label: 'Newest' },
          { value: 'popular', label: 'Popular' },
          { value: 'name', label: 'A-Z' }
        )
      )
    )
  );
}

