function SearchFilterBarWithResults({ query, type, namespace, resultCount, onSearch, onTypeChange, onNamespaceChange, onClearAll }) {
  const { div, span } = tags;
  const hasFilters = query || type !== 'all' || namespace;

  return div({ class: css('_flex _col _gap3') },
    div({ class: css('_flex _aic _gap3') },
      div({ class: css('_flex _aic _gap2 _flex1 _border _bordermuted/20 _r2 _px3 _py2') },
        icon('search', { size: '1rem', class: css('_fgmuted') }),
        Input({ type: 'text', value: query, placeholder: 'Search registry...', class: css('_flex1 _border0 _outline0 _bgcanvas _textsm'), oninput: (e) => onSearch(e.target.value) })
      ),
      Select({ size: 'sm', value: type, onchange: (e) => onTypeChange(e.target.value) },
        { value: 'all', label: 'All types' },
        { value: 'patterns', label: 'Patterns' },
        { value: 'themes', label: 'Themes' },
        { value: 'blueprints', label: 'Blueprints' }
      )
    ),
    div({ class: css('_flex _aic _gap2') },
      span({ class: css('_textsm _fgmuted') }, `${resultCount} results`),
      hasFilters
        ? div({ class: css('_flex _gap1') },
            query ? Badge({ variant: 'secondary', size: 'xs', onclick: () => onSearch('') }, `"${query}" `, icon('x', { size: '0.625rem' })) : null,
            type !== 'all' ? Badge({ variant: 'secondary', size: 'xs', onclick: () => onTypeChange('all') }, type, ' ', icon('x', { size: '0.625rem' })) : null,
            Button({ variant: 'ghost', size: 'xs', onclick: onClearAll }, 'Clear all')
          )
        : null
    )
  );
}

